julia> O = Diagonal(rand(Float64, 25, 25));

julia> P = rand(Float64, 25, 25);

# Shows type unstable return type
julia> @code_warntype O/P

Variables
  #self#::Core.Const(/)
  A::Diagonal{Float64, Vector{Float64}}
  B::Matrix{Float64}

Body::Any
1 ─ %1  = LinearAlgebra.size(A, 2)::Int64
│   %2  = LinearAlgebra.size(B, 2)::Int64
│   %3  = (%1 != %2)::Bool
└──       goto JuliaLang/julia#3 if not %3
2 ─ %5  = LinearAlgebra.DimensionMismatch("Both inputs should have the same number of columns")::Any
│         LinearAlgebra.throw(%5)
└──       Core.Const(:(goto %8))
3 ┄ %8  = LinearAlgebra.adjoint(B)::Adjoint{Float64, Matrix{Float64}}
│   %9  = LinearAlgebra.adjoint(A)::Diagonal{Float64, Vector{Float64}}
│   %10 = (%8 \ %9)::Union{Diagonal{Float64, Vector{Float64}}, SparseArrays.SparseMatrixCSC{Float64, Int64}, Matrix{Float64}}
│   %11 = LinearAlgebra.adjoint(%10)::Union{Diagonal{Float64, Vector{Float64}}, Adjoint{Float64, S} where S}
│   %12 = LinearAlgebra.copy(%11)::Any
└──       return %12
